class Solution:
    def equalPairs(self, grid):
        from collections import Counter
        rows = Counter(tuple(r) for r in grid)
        n = len(grid)
        total = 0
        for c in range(n):
            col = tuple(grid[r][c] for r in range(n))
            total += rows.get(col, 0)
        return total

