var equalPairs = function(grid) {
    const n = grid.length;
    const rows = new Map();
    for (const r of grid) {
        const key = r.join(',');
        rows.set(key, (rows.get(key) || 0) + 1);
    }
    let total = 0;
    for (let c = 0; c < n; c++) {
        const col = [];
        for (let r = 0; r < n; r++) col.push(grid[r][c]);
        const key = col.join(',');
        total += rows.get(key) || 0;
    }
    return total;
};
